from solution import count_words
def test_cw():
    assert count_words('hello world hello') == {'hello':2,'world':1}
    assert count_words('') == {}

from solution import group_by
def test_group_by():
    res = group_by([1,2,3,4], lambda x: x%2)
    assert set(res.keys()) == {0,1}
    assert sorted(res[0]) == [2,4]
    assert sorted(res[1]) == [1,3]

from solution import topological_sort
def test_topo():
    g = {'a':['c'],'b':['c','d'],'c':['e'],'d':['f'],'e':[],'f':[]}
    order = topological_sort(g)
    assert order.index('a') < order.index('c') < order.index('e')
    assert order.index('b') < order.index('d') < order.index('f')

from solution import parse_json_safe
def test_pjs():
    assert parse_json_safe('{"a":1}') == {'a':1}
    assert parse_json_safe('bad') is None
    assert parse_json_safe('null') is None
